import React, { useState } from "react";
import "./Login.css";

interface LoginProps {
  onLogin: (name: string, account: string) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [cpf, setCpf] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const formatCpf = (value: string) => {
    const nums = value.replace(/\D/g, "").slice(0, 11);
    return nums
      .replace(/(\d{3})(\d)/, "$1.$2")
      .replace(/(\d{3})\.(\d{3})(\d)/, "$1.$2.$3")
      .replace(/(\d{3})\.(\d{3})\.(\d{3})(\d)/, "$1.$2.$3-$4");
  };

  // FIX: Added CPF length validation (must be 14 chars formatted) and password min length
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    if (!cpf || !password) {
      setError("Preencha todos os campos.");
      return;
    }
    const rawCpf = cpf.replace(/\D/g, "");
    if (rawCpf.length !== 11) {
      setError("CPF inválido. Digite os 11 dígitos.");
      return;
    }
    if (password.length < 6) {
      setError("A senha deve ter no mínimo 6 caracteres.");
      return;
    }
    setLoading(true);
    setTimeout(() => {
      setLoading(false);
      onLogin("Ana Carolina", "0001 2345-6");
    }, 1400);
  };

  // FIX: replace href="#" with button to prevent page scroll-to-top
  const handleForgotPassword = (e: React.MouseEvent) => {
    e.preventDefault();
  };

  const handleOpenAccount = (e: React.MouseEvent) => {
    e.preventDefault();
  };

  return (
    <div className="login-root">
      <div className="login-left">
        <div className="login-left-content">
          <div className="brand">
            <span className="brand-icon">◆</span>
            <span className="brand-name">NovaBanco</span>
          </div>
          <h1 className="login-headline">
            Seu dinheiro,<br />
            <span className="accent">no seu ritmo.</span>
          </h1>
          <p className="login-subtext">
            Controle total das suas finanças com tecnologia de ponta e segurança bancária real.
          </p>
          <div className="login-stats">
            <div className="stat">
              <span className="stat-value">2M+</span>
              <span className="stat-label">Clientes</span>
            </div>
            <div className="stat-divider" />
            <div className="stat">
              <span className="stat-value">R$8B</span>
              <span className="stat-label">Movimentados</span>
            </div>
            <div className="stat-divider" />
            <div className="stat">
              <span className="stat-value">4.9★</span>
              <span className="stat-label">Avaliação</span>
            </div>
          </div>
        </div>
        <div className="login-bg-shapes">
          <div className="shape shape-1" />
          <div className="shape shape-2" />
          <div className="shape shape-3" />
        </div>
      </div>

      <div className="login-right">
        <div className="login-card">
          <div className="login-card-header">
            <h2>Bem-vindo de volta</h2>
            <p>Acesse sua conta com segurança</p>
          </div>

          <form onSubmit={handleSubmit} className="login-form" noValidate>
            <div className="field-group">
              <label htmlFor="cpf-input">CPF</label>
              <div className="input-wrapper">
                <span className="input-icon">👤</span>
                <input
                  id="cpf-input"
                  type="text"
                  inputMode="numeric"
                  placeholder="000.000.000-00"
                  value={cpf}
                  onChange={(e) => setCpf(formatCpf(e.target.value))}
                  autoComplete="username"
                />
              </div>
            </div>

            <div className="field-group">
              <label htmlFor="password-input">Senha</label>
              <div className="input-wrapper">
                <span className="input-icon">🔒</span>
                <input
                  id="password-input"
                  type="password"
                  placeholder="••••••••"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  autoComplete="current-password"
                />
              </div>
            </div>

            {error && <div className="login-error" role="alert">{error}</div>}

            {/* FIX: href="#" replaced with button to prevent scroll jump */}
            <button
              type="button"
              className="forgot-link"
              onClick={handleForgotPassword}
            >
              Esqueceu a senha?
            </button>

            <button
              type="submit"
              className={`btn-login ${loading ? "loading" : ""}`}
              disabled={loading}
            >
              {loading ? <span className="spinner" /> : "Entrar na conta"}
            </button>
          </form>

          <div className="login-footer">
            <span>Não tem conta?</span>
            {/* FIX: href="#" replaced with button */}
            <button type="button" className="open-account-link" onClick={handleOpenAccount}>
              Abra a sua grátis →
            </button>
          </div>

          <div className="security-badge">
            <span>🔐</span>
            <span>Conexão criptografada SSL 256-bit</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
